import React from 'react';
import './style.css';

const Contact = () => {
    return (
        <section id="contact" className="contact">
            <h2>Contact Me</h2>
            <p>Email: <a href="mailto:dantemienie@gmail.com">dantemienie@gmail.com</a></p>
            <p><a href="https://www.linkedin.com/in/dante-mienie/" target="_blank" rel="noopener noreferrer">LinkedIn</a></p>
        </section>
    );
};

export default Contact;
